```tsx
"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    step: 1,
    title: "Account",
    description: "Create your account",
  },
  {
    step: 2,
    title: "Profile",
    description: "Set up your profile",
  },
  {
    step: 3,
    title: "Complete",
    description: "Review and finish",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(1)

  return (
    <div className="flex w-full max-w-lg flex-col gap-6">
      <Stepper activeStep={activeStep}>
        {steps.map(({ step, title, description }) => (
          <StepperItem key={step} step={step}>
            <StepperTrigger onClick={() => setActiveStep(step)} />
            <div>
              <StepperTitle>{title}</StepperTitle>
              <StepperDescription>{description}</StepperDescription>
            </div>
            {step < steps.length && <StepperSeparator />}
          </StepperItem>
        ))}
        <StepperContent step={1}>
          <p className="text-sm text-muted-foreground">
            Enter your email and password to create your account.
          </p>
        </StepperContent>
        <StepperContent step={2}>
          <p className="text-sm text-muted-foreground">
            Tell us about yourself. This information will be visible on your
            profile.
          </p>
        </StepperContent>
        <StepperContent step={3}>
          <p className="text-sm text-muted-foreground">
            Review your information and confirm to complete the setup.
          </p>
        </StepperContent>
      </Stepper>
      <div className="flex gap-2">
        <Button
          variant="outline"
          onClick={() => setActiveStep((prev) => Math.max(1, prev - 1))}
          disabled={activeStep <= 1}
        >
          Previous
        </Button>
        <Button
          onClick={() =>
            setActiveStep((prev) => Math.min(steps.length, prev + 1))
          }
          disabled={activeStep >= steps.length}
        >
          Next
        </Button>
      </div>
    </div>
  )
}
```

Key design choices in the demo:
- `"use client"` is needed because of `React.useState`.
- Follows the `tabs-demo.tsx` pattern: imports from `@/registry/new-york-v4/ui/...`, default export function, wraps content in a container div with `max-w-lg`.
- Uses `Button` component (consistent with the codebase using its own button).
- Steps are mapped from a data array for clean rendering.
- `StepperContent` elements are siblings to `StepperItem` elements (both direct children of `Stepper`), not nested inside `StepperItem`.
- Navigation buttons are outside the `Stepper` component.

